// Extrai preço atual e calcula variação percentual em relação ao preço de referência
const item = $input.first();
const quote = item.json['Global Quote'];

const ticker = $('Loop Over Items').item.json.ticker;
const precoRef = parseFloat($('Loop Over Items').item.json.preco_referencia);
const precoAtual = parseFloat(quote['05. price']);
const variacaoAbs = precoAtual - precoRef;
const variacaoPerc = ((precoAtual - precoRef) / precoRef) * 100;

return [{
  json: {
    ticker: ticker,
    preco_referencia: precoRef,
    preco_atual: precoAtual,
    variacao_abs: parseFloat(variacaoAbs.toFixed(2)),
    variacao_perc: parseFloat(variacaoPerc.toFixed(2)),
    sinal: variacaoPerc >= 0 ? '📈' : '📉',
    timestamp: new Date().toISOString()
  }
}];

// Formata as notícias para enviar ao ChatGPT
const item = $input.first();
const articles = item.json.articles || [];

const ticker = $('Calcular Variação Percentual').item.json.ticker;
const variacaoPerc = $('Calcular Variação Percentual').item.json.variacao_perc;
const precoAtual = $('Calcular Variação Percentual').item.json.preco_atual;
const precoRef = $('Calcular Variação Percentual').item.json.preco_referencia;
const sinal = $('Calcular Variação Percentual').item.json.sinal;

const noticias = articles
  .slice(0, 5)
  .map((a, i) => `${i + 1}. ${a.title}\n   Fonte: ${a.source?.name || 'N/A'}\n   ${a.description || ''}`)
  .join('\n\n');

const promptAnalise = `Você é um analista financeiro especializado em mercado de capitais brasileiro. Analise as notícias abaixo referentes à ação ${ticker} e responda EXATAMENTE neste formato JSON (sem markdown, sem texto fora do JSON):

{
  "sentimento": "POSITIVO" ou "NEUTRO" ou "NEGATIVO",
  "confianca": numero de 0 a 100,
  "resumo_noticias": "resumo em 2-3 frases das principais notícias",
  "correlacao_preco": "explicação em 1-2 frases correlacionando o sentimento das notícias com a variação de ${variacaoPerc > 0 ? '+' : ''}${variacaoPerc}% observada no preço",
  "principais_fatores": ["fator 1", "fator 2", "fator 3"]
}

Contexto do preço:
- Ticker: ${ticker}
- Preço de referência: R$ ${precoRef}
- Preço atual: R$ ${precoAtual}
- Variação: ${sinal} ${variacaoPerc > 0 ? '+' : ''}${variacaoPerc}%

Notícias encontradas:
${noticias || 'Nenhuma notícia encontrada para este ticker.'}`;

return [{
  json: {
    ticker,
    variacao_perc: variacaoPerc,
    preco_atual: precoAtual,
    preco_ref: precoRef,
    sinal,
    noticias_raw: noticias,
    prompt_analise: promptAnalise,
    timestamp: $('Calcular Variação Percentual').item.json.timestamp
  }
}];

// Monta o e-mail de alerta e os dados para registro no histórico
const gptRaw = $input.first().json.message?.content || '{}';
let analise = {};
try {
  analise = JSON.parse(gptRaw.replace(/```json|```/g, '').trim());
} catch(e) {
  analise = { sentimento: 'INDISPONÍVEL', confianca: 0, resumo_noticias: gptRaw.substring(0, 300), correlacao_preco: '', principais_fatores: [] };
}

const prev = $('Preparar Prompt de Análise').item.json;
const ticker = prev.ticker;
const variacaoPerc = prev.variacao_perc;
const precoAtual = prev.preco_atual;
const precoRef = prev.preco_ref;
const sinal = prev.sinal;
const timestamp = prev.timestamp;

const sentimentoCor = {
  POSITIVO: '#27ae60',
  NEUTRO: '#f39c12',
  NEGATIVO: '#e74c3c',
  INDISPONÍVEL: '#95a5a6'
};

const sentimentoEmoji = {
  POSITIVO: '🟢',
  NEUTRO: '🟡',
  NEGATIVO: '🔴',
  INDISPONÍVEL: '⚪'
};

const cor = sentimentoCor[analise.sentimento] || '#95a5a6';
const emoji = sentimentoEmoji[analise.sentimento] || '⚪';
const varSign = variacaoPerc > 0 ? '+' : '';
const fatores = (analise.principais_fatores || []).map(f => `<li>${f}</li>`).join('');

const dataFormatada = new Date(timestamp).toLocaleDateString('pt-BR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit'
});

const corpoEmail = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;">
  <div style="background:#1a1a2e;padding:20px 24px;border-radius:8px 8px 0 0;">
    <h2 style="color:#fff;margin:0;font-size:20px;">📊 Alerta de Ação — ${ticker}</h2>
    <p style="color:#aaa;margin:4px 0 0;font-size:12px;">${dataFormatada}</p>
  </div>
  <div style="background:#fff;border:1px solid #e0e0e0;border-top:none;padding:24px;border-radius:0 0 8px 8px;">

    <table style="width:100%;border-collapse:collapse;margin-bottom:20px;">
      <tr>
        <td style="padding:10px;background:#f8f9fa;border-radius:6px;text-align:center;">
          <div style="font-size:28px;font-weight:bold;color:#1a1a2e;">${ticker}</div>
          <div style="font-size:12px;color:#666;">Ticker</div>
        </td>
        <td style="width:16px;"></td>
        <td style="padding:10px;background:#f8f9fa;border-radius:6px;text-align:center;">
          <div style="font-size:24px;font-weight:bold;color:#1a1a2e;">R$ ${precoAtual}</div>
          <div style="font-size:12px;color:#666;">Preço Atual</div>
        </td>
        <td style="width:16px;"></td>
        <td style="padding:10px;background:${cor}15;border:1.5px solid ${cor};border-radius:6px;text-align:center;">
          <div style="font-size:24px;font-weight:bold;color:${cor};">${sinal} ${varSign}${variacaoPerc}%</div>
          <div style="font-size:12px;color:#666;">Variação vs Ref. (R$ ${precoRef})</div>
        </td>
      </tr>
    </table>

    <div style="background:${cor}10;border-left:4px solid ${cor};padding:14px 16px;border-radius:0 6px 6px 0;margin-bottom:20px;">
      <div style="font-size:14px;font-weight:bold;color:${cor};margin-bottom:4px;">${emoji} Sentimento: ${analise.sentimento} — Confiança: ${analise.confianca}%</div>
      <p style="margin:0;font-size:13px;color:#333;">${analise.correlacao_preco || ''}</p>
    </div>

    <h3 style="font-size:14px;color:#333;margin-bottom:8px;">📰 Resumo das Notícias</h3>
    <p style="font-size:13px;color:#555;line-height:1.6;margin-bottom:16px;">${analise.resumo_noticias || 'Sem notícias disponíveis.'}</p>

    ${fatores ? `<h3 style="font-size:14px;color:#333;margin-bottom:8px;">🔑 Principais Fatores</h3><ul style="font-size:13px;color:#555;line-height:1.8;padding-left:20px;">${fatores}</ul>` : ''}

    <hr style="border:none;border-top:1px solid #eee;margin:20px 0;"/>
    <p style="font-size:11px;color:#aaa;margin:0;">Gerado automaticamente pelo seu workflow n8n ⚡ — Não constitui recomendação de investimento.</p>
  </div>
</div>`;

const dataHoje = new Date(timestamp).toLocaleDateString('pt-BR');
const horaAgora = new Date(timestamp).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

return [{
  json: {
    ticker,
    variacao_perc: variacaoPerc,
    preco_atual: precoAtual,
    preco_ref: precoRef,
    sentimento: analise.sentimento,
    confianca: analise.confianca,
    resumo_noticias: analise.resumo_noticias,
    correlacao_preco: analise.correlacao_preco,
    principais_fatores: (analise.principais_fatores || []).join(' | '),
    data: dataHoje,
    hora: horaAgora,
    email_assunto: `${sinal} ALERTA: ${ticker} ${varSign}${variacaoPerc}% — Sentimento ${analise.sentimento}`,
    email_corpo: corpoEmail
  }
}];

// Ação sem variação relevante — apenas registra sem enviar e-mail
const item = $input.first();
const ticker = item.json.ticker;
const variacaoPerc = item.json.variacao_perc;
const precoAtual = item.json.preco_atual;
const sinal = item.json.sinal;

console.log(`[SEM ALERTA] ${ticker} — variação de ${variacaoPerc}% está dentro do limite de ±3%. Nenhum alerta enviado.`);

return [{
  json: {
    status: 'sem_alerta',
    ticker,
    variacao_perc: variacaoPerc,
    preco_atual: precoAtual,
    mensagem: `${ticker} com variação de ${variacaoPerc}% está dentro do limite (±3%). Monitoramento normal.`
  }
}];

